// ── URGENCY ROUTER ─────────────────────────────────────────────────────────
// Spec: urgency values = critical | high | medium | low  (always lowercase)
//       status values  = pending | sent | dismissed | snoozed
//       trend values   = improving | stable | at_risk | declining
//       tag values     = close_friend | family | work | mentor | romantic | acquaintance
//       health_score   = 0-100 integer

const summary = $('📊 GET /api/contacts/summary').item.json;
const raw     = $('📋 GET /api/actions?status=pending').item.json;

// Actions array may be top-level or nested under .actions
const actions = Array.isArray(raw) ? raw : (raw.actions || []);

// Split into urgency buckets
const buckets = { critical: [], high: [], medium: [], low: [] };
for (const a of actions) {
  const u = (a.urgency || 'low').toLowerCase();
  (buckets[u] || buckets.low).push(a);
}

// Normalise one action into a clean object
const fmt = a => ({
  action_id:         String(a.action_id || ''),
  contact_id:        a.contact_id        || '',
  contact_name:      a.contact_name      || 'Unknown',
  tag:               a.tag               || '',
  urgency:           (a.urgency          || 'low').toLowerCase(),
  action_type:       a.action_type       || 'reconnect',
  reason:            a.reason            || '',
  suggested_message: a.suggested_message || '',
  phone_number:      a.phone_number      || '',
  status:            a.status            || 'pending',
});

return [{ json: {
  critical:       buckets.critical.map(fmt),
  high:           buckets.high.map(fmt),
  medium:         buckets.medium.map(fmt),
  low:            buckets.low.map(fmt),
  total:          actions.length,
  critical_count: buckets.critical.length,
  high_count:     buckets.high.length,
  avg_health:     Math.round(summary.avg_health_score || 0),
  total_contacts: summary.total           || 0,
  ghosted_count:  summary.ghosted_count   || 0,
  drifting_count: summary.drifting_count  || 0,
  has_critical:   buckets.critical.length > 0,
  has_any:        actions.length > 0,
}}];

// CRITICAL ALERT — fires when urgency=critical actions exist
// Tag colour palette matches the frontend neo-brutalism design system
const d   = $input.item.json;
const now = new Date().toLocaleDateString('en-IN', {
  weekday: 'long', day: 'numeric', month: 'long', year: 'numeric'
});

// Tag colours — close_friend|family|work|mentor|romantic|acquaintance
const TAG_BG = { close_friend:'#AFFFB0', family:'#7B61FF', work:'#00BFFF', mentor:'#F5FF4E', romantic:'#FF6BBA', acquaintance:'#e0e0e0' };
const TAG_FG = { family:'#fff', close_friend:'#111', work:'#111', mentor:'#111', romantic:'#111', acquaintance:'#555' };

const card = a => {
  const tag = a.tag
    ? `<span style="background:${TAG_BG[a.tag]||'#e0e0e0'};color:${TAG_FG[a.tag]||'#111'};border:1.5px solid #111;padding:1px 8px;font-size:9px;font-weight:800;letter-spacing:1px;margin-left:8px;vertical-align:middle;">${a.tag.replace(/_/g,' ').toUpperCase()}</span>`
    : '';
  return `
  <div style="border:3px solid #FF4545;background:#fff;padding:16px 18px;margin-bottom:14px;box-shadow:5px 5px 0 #FF4545;">
    <div style="display:flex;justify-content:space-between;align-items:flex-start;margin-bottom:8px;">
      <div style="line-height:1.6;"><b style="font-size:15px;">${a.contact_name}</b>${tag}</div>
      <span style="background:#FF4545;color:#fff;padding:3px 10px;font-size:10px;font-weight:800;letter-spacing:1px;border:1px solid #111;white-space:nowrap;margin-left:12px;">CRITICAL</span>
    </div>
    <div style="background:#111;color:#AFFFB0;display:inline-block;padding:2px 9px;font-size:10px;font-weight:800;letter-spacing:2px;margin-bottom:8px;">${a.action_type.replace(/_/g,' ').toUpperCase()}</div>
    <div style="font-size:12px;color:#555;margin-bottom:10px;">${a.reason}</div>
    <div style="background:#fffbf5;border-left:4px solid #FF4545;padding:10px 14px;font-style:italic;font-size:13px;line-height:1.5;">&ldquo;${a.suggested_message}&rdquo;</div>
  </div>`;
};

return [{ json: {
  subject: `🔴 CRITICAL — ${d.critical_count} relationship(s) need attention NOW`,
  html: `<!DOCTYPE html><html><body style="font-family:monospace;background:#F5F0E8;margin:0;padding:0;">
<div style="max-width:600px;margin:0 auto;padding:24px;">

  <div style="background:#111;color:#AFFFB0;padding:18px 22px;border:3px solid #111;">
    <div style="font-size:28px;letter-spacing:4px;font-weight:800;">AUTOPILOT SOCIAL</div>
    <div style="color:#FF4545;font-size:10px;letter-spacing:3px;margin-top:6px;">🔴 CRITICAL ALERT &nbsp;·&nbsp; ${now}</div>
  </div>

  <div style="background:#FF4545;color:#fff;border:3px solid #111;border-top:none;padding:12px 22px;font-weight:800;letter-spacing:1px;">
    ${d.critical_count} CONTACT(S) NEED YOUR ATTENTION TODAY
  </div>

  <div style="background:#fff;border:3px solid #111;border-top:none;padding:20px 20px 6px;">
    ${d.critical.map(card).join('')}
  </div>

  <div style="display:grid;grid-template-columns:repeat(4,1fr);gap:10px;margin-top:12px;">
    <div style="background:#AFFFB0;border:3px solid #111;padding:14px;text-align:center;box-shadow:4px 4px 0 #111;"><div style="font-size:9px;letter-spacing:2px;opacity:.6;">CONTACTS</div><div style="font-size:32px;font-weight:800;">${d.total_contacts}</div></div>
    <div style="background:#fff;border:3px solid #111;padding:14px;text-align:center;box-shadow:4px 4px 0 #7B61FF;"><div style="font-size:9px;letter-spacing:2px;opacity:.6;">AVG HEALTH</div><div style="font-size:32px;font-weight:800;color:#7B61FF;">${d.avg_health}</div></div>
    <div style="background:#fff;border:3px solid #111;padding:14px;text-align:center;box-shadow:4px 4px 0 #FF4545;"><div style="font-size:9px;letter-spacing:2px;opacity:.6;">GHOSTED</div><div style="font-size:32px;font-weight:800;color:#FF4545;">${d.ghosted_count}</div></div>
    <div style="background:#F5FF4E;border:3px solid #111;padding:14px;text-align:center;box-shadow:4px 4px 0 #111;"><div style="font-size:9px;letter-spacing:2px;opacity:.6;">AT RISK</div><div style="font-size:32px;font-weight:800;">${d.drifting_count}</div></div>
  </div>

  <div style="margin-top:14px;font-size:10px;opacity:.35;text-align:center;letter-spacing:2px;">AUTOPILOT SOCIAL &nbsp;·&nbsp; AUTOMATED DIGEST</div>
</div></body></html>`,
}}];

// 6H DIGEST — all pending actions grouped by urgency
const d   = $input.item.json;
const now = new Date().toLocaleDateString('en-IN', {
  weekday: 'long', day: 'numeric', month: 'long', year: 'numeric'
});

const TAG_BG = { close_friend:'#AFFFB0', family:'#7B61FF', work:'#00BFFF', mentor:'#F5FF4E', romantic:'#FF6BBA', acquaintance:'#e0e0e0' };
const TAG_FG = { family:'#fff', close_friend:'#111', work:'#111', mentor:'#111', romantic:'#111', acquaintance:'#555' };
const URG_BG = { critical:'#FF4545', high:'#F5FF4E', medium:'#D8F0FF', low:'#f0f0f0' };
const URG_FG = { critical:'#fff',    high:'#111',    medium:'#111',    low:'#666'  };

const card = a => {
  const tag = a.tag
    ? `<span style="background:${TAG_BG[a.tag]||'#e0e0e0'};color:${TAG_FG[a.tag]||'#111'};border:1.5px solid #111;padding:1px 8px;font-size:9px;font-weight:800;letter-spacing:1px;margin-left:8px;vertical-align:middle;">${a.tag.replace(/_/g,' ').toUpperCase()}</span>`
    : '';
  return `
  <div style="border:2px solid #111;background:#fff;padding:14px 16px;margin-bottom:10px;box-shadow:4px 4px 0 #111;">
    <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:6px;">
      <div style="line-height:1.6;"><b>${a.contact_name}</b>${tag}</div>
      <span style="background:${URG_BG[a.urgency]||'#eee'};color:${URG_FG[a.urgency]||'#111'};border:2px solid #111;padding:2px 9px;font-size:10px;font-weight:800;white-space:nowrap;margin-left:10px;">${a.urgency.toUpperCase()}</span>
    </div>
    <div style="font-size:10px;color:#7B61FF;font-weight:800;letter-spacing:1px;margin-bottom:5px;">${a.action_type.replace(/_/g,' ').toUpperCase()}</div>
    <div style="font-size:11px;color:#666;margin-bottom:9px;">${a.reason}</div>
    <div style="background:#F5F0E8;border-left:3px solid #111;padding:8px 12px;font-style:italic;font-size:12px;line-height:1.5;">&ldquo;${a.suggested_message}&rdquo;</div>
  </div>`;
};

const all = [...d.critical, ...d.high, ...d.medium, ...d.low];

return [{ json: {
  subject: `📊 Autopilot Digest — ${d.total} action(s) pending  ·  ${now}`,
  html: `<!DOCTYPE html><html><body style="font-family:monospace;background:#F5F0E8;margin:0;padding:0;">
<div style="max-width:600px;margin:0 auto;padding:24px;">

  <div style="background:#111;color:#AFFFB0;padding:18px 22px;border:3px solid #111;">
    <div style="font-size:28px;letter-spacing:4px;font-weight:800;">AUTOPILOT SOCIAL</div>
    <div style="color:#F5FF4E;font-size:10px;letter-spacing:3px;margin-top:6px;">6H RELATIONSHIP DIGEST &nbsp;·&nbsp; ${now}</div>
  </div>

  <div style="background:#AFFFB0;border:3px solid #111;border-top:none;padding:12px 22px;font-weight:800;letter-spacing:1px;">
    ${d.total} PENDING ACTION(S) &nbsp;·&nbsp; ${d.ghosted_count} GHOSTED &nbsp;·&nbsp; ${d.drifting_count} AT RISK
  </div>

  <div style="background:#fff;border:3px solid #111;border-top:none;padding:18px 18px 6px;">
    ${all.length ? all.map(card).join('') : '<div style="text-align:center;padding:30px;opacity:.4;letter-spacing:2px;">ALL CLEAR — NO PENDING ACTIONS</div>'}
  </div>

  <div style="margin-top:14px;font-size:10px;opacity:.35;text-align:center;letter-spacing:2px;">AUTOPILOT SOCIAL &nbsp;·&nbsp; SENT EVERY 6 HOURS</div>
</div></body></html>`,
}}];

// MONDAY WEEKLY REPORT
// trend: improving | stable | at_risk | declining
// tag:   close_friend | family | work | mentor | romantic | acquaintance
// health_score: 0-100 integer

const summary  = $('📊 Weekly: GET /api/contacts/summary').item.json;
const atRisk   = ($('⚠️ Weekly: GET contacts trend=at_risk').item.json.contacts   || []).slice(0,6);
const declining= ($('📉 Weekly: GET contacts trend=declining').item.json.contacts || []).slice(0,6);

const week = new Date().toLocaleDateString('en-IN', { day: 'numeric', month: 'long', year: 'numeric' });

const TAG_BG = { close_friend:'#AFFFB0', family:'#7B61FF', work:'#00BFFF', mentor:'#F5FF4E', romantic:'#FF6BBA', acquaintance:'#e0e0e0' };
const TAG_FG = { family:'#fff', close_friend:'#111', work:'#111', mentor:'#111', romantic:'#111', acquaintance:'#555' };

// trend → arrow icon, background chip colour
const TREND_ICON  = { improving:'↑', stable:'→', at_risk:'⚠', declining:'↓' };
const TREND_COLOR = { improving:'#AFFFB0', stable:'#e0e0e0', at_risk:'#F5FF4E', declining:'#FF4545' };
const TREND_FG    = { improving:'#111', stable:'#555', at_risk:'#111', declining:'#fff' };

// health_score 0-100 → traffic-light colour
const scoreColor = s => s >= 70 ? '#AFFFB0' : s >= 40 ? '#F5FF4E' : '#FF4545';

const contactRow = c => {
  const score = Math.round(c.health_score || 0);
  const trend = c.trend || 'stable';
  const tag   = c.tag
    ? `<span style="background:${TAG_BG[c.tag]||'#e0e0e0'};color:${TAG_FG[c.tag]||'#111'};border:1.5px solid #111;padding:1px 7px;font-size:9px;font-weight:800;letter-spacing:1px;margin-left:8px;">${c.tag.replace(/_/g,' ').toUpperCase()}</span>`
    : '';
  return `
  <div style="border:2px solid #111;background:#fff;padding:12px 14px;margin-bottom:8px;box-shadow:3px 3px 0 #111;display:flex;justify-content:space-between;align-items:center;">
    <div>
      <div style="display:flex;align-items:center;flex-wrap:wrap;"><b>${c.name || c.contact_id}</b>${tag}</div>
      <div style="font-size:10px;color:#888;margin-top:3px;">${c.total_messages||0} messages &nbsp;·&nbsp; ${c.platform||''}</div>
    </div>
    <div style="display:flex;align-items:center;gap:8px;">
      <span style="background:${TREND_COLOR[trend]||'#e0e0e0'};color:${TREND_FG[trend]||'#111'};border:2px solid #111;width:28px;height:28px;display:inline-flex;align-items:center;justify-content:center;font-weight:800;font-size:14px;">${TREND_ICON[trend]||'?'}</span>
      <span style="font-size:26px;font-weight:800;color:${scoreColor(score)};border:2px solid #111;padding:2px 8px;">${score}</span>
    </div>
  </div>`;
};

const section = (title, items) => items.length === 0 ? '' : `
  <div style="margin-top:18px;">
    <div style="font-size:10px;letter-spacing:2px;opacity:.55;border-bottom:2px solid #111;padding-bottom:6px;margin-bottom:10px;">${title} (${items.length})</div>
    ${items.map(contactRow).join('')}
  </div>`;

return [{ json: {
  subject: `📊 Weekly Relationship Report — ${week}`,
  html: `<!DOCTYPE html><html><body style="font-family:monospace;background:#F5F0E8;margin:0;padding:0;">
<div style="max-width:620px;margin:0 auto;padding:24px;">

  <div style="background:#111;color:#AFFFB0;padding:20px 24px;border:3px solid #111;">
    <div style="font-size:36px;letter-spacing:5px;font-weight:800;">AUTOPILOT</div>
    <div style="color:#F5FF4E;font-size:10px;letter-spacing:3px;margin-top:6px;">WEEKLY RELATIONSHIP REPORT &nbsp;·&nbsp; ${week}</div>
  </div>

  <div style="display:grid;grid-template-columns:repeat(4,1fr);gap:10px;margin-top:12px;">
    <div style="background:#AFFFB0;border:3px solid #111;padding:14px;text-align:center;box-shadow:4px 4px 0 #111;"><div style="font-size:9px;letter-spacing:2px;opacity:.6;">CONTACTS</div><div style="font-size:34px;font-weight:800;">${summary.total||0}</div></div>
    <div style="background:#fff;border:3px solid #111;padding:14px;text-align:center;box-shadow:4px 4px 0 #7B61FF;"><div style="font-size:9px;letter-spacing:2px;opacity:.6;">AVG HEALTH</div><div style="font-size:34px;font-weight:800;color:#7B61FF;">${Math.round(summary.avg_health_score||0)}</div></div>
    <div style="background:#fff;border:3px solid #111;padding:14px;text-align:center;box-shadow:4px 4px 0 #FF4545;"><div style="font-size:9px;letter-spacing:2px;opacity:.6;">GHOSTED</div><div style="font-size:34px;font-weight:800;color:#FF4545;">${summary.ghosted_count||0}</div></div>
    <div style="background:#F5FF4E;border:3px solid #111;padding:14px;text-align:center;box-shadow:4px 4px 0 #111;"><div style="font-size:9px;letter-spacing:2px;opacity:.6;">AT RISK</div><div style="font-size:34px;font-weight:800;">${summary.drifting_count||0}</div></div>
  </div>

  ${section('⚠ AT RISK — NEEDS ATTENTION THIS WEEK', atRisk)}
  ${section('↓ DECLINING — ENGAGEMENT DROPPING', declining)}

  <div style="margin-top:18px;font-size:10px;opacity:.35;text-align:center;letter-spacing:2px;">AUTOPILOT SOCIAL &nbsp;·&nbsp; EVERY MONDAY 8AM</div>
</div></body></html>`,
}}];

// REAL-TIME DRIFT DETECTOR
// Fires an alert email ONLY when contacts NEWLY enter declining/ghosted.
// Uses n8n workflow static data to remember the previous state.
// drift is_ghosted is a boolean on the contact document.

const declining = $('📉 Drift: GET contacts trend=declining').item.json.contacts || [];
const ghosted   = $('👻 Drift: GET contacts is_ghosted=true').item.json.contacts || [];

// Persistent state across runs (stored in n8n)
const store     = $getWorkflowStaticData('global');
const prevDecl  = new Set(store.prevDeclining || []);
const prevGhost = new Set(store.prevGhosted   || []);

// Only contacts that weren't in the last snapshot
const newlyDeclining = declining.filter(c => !prevDecl.has(c.contact_id));
const newlyGhosted   = ghosted.filter(c   => !prevGhost.has(c.contact_id));

// Save current snapshot
store.prevDeclining = declining.map(c => c.contact_id);
store.prevGhosted   = ghosted.map(c   => c.contact_id);

const TAG_BG = { close_friend:'#AFFFB0', family:'#7B61FF', work:'#00BFFF', mentor:'#F5FF4E', romantic:'#FF6BBA', acquaintance:'#e0e0e0' };
const TAG_FG = { family:'#fff', close_friend:'#111', work:'#111', mentor:'#111', romantic:'#111', acquaintance:'#555' };
const scoreColor = s => s >= 70 ? '#AFFFB0' : s >= 40 ? '#F5FF4E' : '#FF4545';
const time = new Date().toLocaleTimeString('en-IN', { hour: '2-digit', minute: '2-digit' });

const miniCard = (c, accent) => {
  const score = Math.round(c.health_score || 0);
  const tag   = c.tag
    ? `<span style="background:${TAG_BG[c.tag]||'#e0e0e0'};color:${TAG_FG[c.tag]||'#111'};border:1.5px solid #111;padding:1px 6px;font-size:9px;font-weight:800;margin-left:8px;">${c.tag.replace(/_/g,' ').toUpperCase()}</span>`
    : '';
  return `
  <div style="border:2px solid ${accent};background:#fff;padding:12px 14px;margin-bottom:8px;box-shadow:3px 3px 0 ${accent};display:flex;justify-content:space-between;align-items:center;">
    <div>
      <div style="display:flex;align-items:center;flex-wrap:wrap;"><b>${c.name||c.contact_id}</b>${tag}</div>
      <div style="font-size:10px;color:#888;margin-top:3px;">${c.total_messages||0} msgs &nbsp;·&nbsp; last seen ${c.days_since||0}d ago</div>
    </div>
    <span style="font-size:24px;font-weight:800;color:${scoreColor(score)};">${score}</span>
  </div>`;
};

const total = newlyDeclining.length + newlyGhosted.length;
const hasAlerts = total > 0;

const declSection  = newlyDeclining.length
  ? `<div style="margin-top:14px;"><div style="font-size:10px;letter-spacing:2px;opacity:.55;margin-bottom:8px;border-bottom:2px solid #111;padding-bottom:5px;">↓ NEWLY DECLINING (${newlyDeclining.length})</div>${newlyDeclining.map(c=>miniCard(c,'#F5FF4E')).join('')}</div>`
  : '';
const ghostSection = newlyGhosted.length
  ? `<div style="margin-top:14px;"><div style="font-size:10px;letter-spacing:2px;opacity:.55;margin-bottom:8px;border-bottom:2px solid #111;padding-bottom:5px;">👻 NEWLY GHOSTED (${newlyGhosted.length})</div>${newlyGhosted.map(c=>miniCard(c,'#FF4545')).join('')}</div>`
  : '';

return [{ json: {
  hasAlerts,
  total,
  subject: `⚡ Live Drift Alert — ${total} new change(s) at ${time}`,
  html: `<!DOCTYPE html><html><body style="font-family:monospace;background:#F5F0E8;margin:0;padding:0;">
<div style="max-width:580px;margin:0 auto;padding:24px;">
  <div style="background:#111;color:#AFFFB0;padding:16px 22px;border:3px solid #111;">
    <div style="font-size:24px;letter-spacing:4px;font-weight:800;">AUTOPILOT — LIVE</div>
    <div style="color:#FF4545;font-size:10px;letter-spacing:3px;margin-top:5px;">⚡ REAL-TIME DRIFT ALERT &nbsp;·&nbsp; ${time}</div>
  </div>
  ${declSection}${ghostSection}
  <div style="margin-top:16px;font-size:10px;opacity:.35;text-align:center;letter-spacing:2px;">AUTOPILOT SOCIAL &nbsp;·&nbsp; CHECKS EVERY 30 MINUTES</div>
</div></body></html>`,
}}];

// N8N_SEND_MESSAGE_WEBHOOK handler
// Triggered from frontend /alerts and /reminders when user clicks "Send"
