  ok:             true,
  message:        'n8n is connected and responding to Autopilot Social',
  timestamp:      new Date().toISOString(),
  active_flows: [
    '6h pipeline trigger + digest email',
    'monday weekly report',
    '30min real-time drift alerts',
    'send message dispatcher (WhatsApp/Telegram)',
    'action status feedback loop',
  ],
}}];
